VALUES
  ('bookkeeper-moex-00172', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據所得稅法，關於「非中華民國境內居住之個人」而有中華民國來源所得者的所得稅課徵，下列敘 述何者錯誤？', '["屬扣繳範圍之所得，應由扣繳義務人按各類所得扣繳率就源扣繳，無須辦理結算申報", "不屬扣繳範圍之所得，如財產交易所得與一時貿易盈餘所得等，應按規定扣繳率申報納稅", "外籍人士於同一課稅年度內在中華民國境內居留只要合計未滿183天，在中華民國境內提供勞務而 自境外雇主取得的勞務報酬，不屬於中華民國來源所得，免課徵所得稅", "於一課稅年度內，在中華民國境內有住所，但非經常居住中華民國境內，屬於非中華民國境內居住 之個人。扣繳義務人給付該個人各類所得時，應於給付時依規定之扣繳率扣取稅款"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00173', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據所得稅法，下列何者屬於列舉扣除額的項目？①災害損失  ②財產交易損失  ③長期照顧', '["房屋租金支出  ⑤自用住宅購屋借款利息  ⑥教育學費", "僅", "⑤", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00174', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據所得稅法，有關營利事業所得稅的暫繳規定，下列敘述何者錯誤？', '["營利事業原則上應於每年9月1日起至9月30日止，按其上年度結算申報營利事業所得稅應納稅 額之1/3為暫繳稅額，自行向庫繳納", "公司組織之營利事業，會計帳冊簿據完備，使用藍色申報書或經會計師查核簽證，並如期辦理暫繳 申報者，得以當年度前6個月之營業收入總額，試算其前半年之營利事業所得額，按當年度稅率， 計算其暫繳稅額", "獨資、合夥組織之營利事業及經核定之小規模營利事業，免辦理暫繳", "營利事業未以投資抵減稅額、行政救濟留抵稅額及扣繳稅額抵減暫繳稅額者，於自行向庫繳納暫繳 稅款後，得免辦理暫繳申報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00175', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據所得稅法，有關扣繳義務人給付各類所得所扣取稅款的處理，下列敘述何者錯誤？', '["應於每月15日前將上一月內所扣稅款向國庫繳清", "應於每年1月底前將上一年內扣繳各納稅義務人之稅款數額，開具扣繳憑單，彙報該管稽徵機關查核", "應於每年2月10日前將扣繳憑單填發納稅義務人", "扣繳義務人針對非中華民國境內居住之個人，或在中華民國境內無固定營業場所之營利事業所扣取 的稅款，應於代扣稅款之日起10日內，將所扣稅款向國庫繳清，並開具扣繳憑單，發給納稅義務人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00176', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲君 112 年度的綜合所得淨額為 5,000,000 元，一般所得稅額為 1,200,000 元。甲君另有海外所得 5,000,000元、受益人與要保人非屬同一人的人壽保險給付1,000,000元、上市櫃股票交易所得1,000,000 元、未上市櫃股票交易所得1,500,000元、申報綜合所得稅時減除的現金捐贈金額500,000元與非現 金捐贈金額500,000元。計算基本稅額的扣除金額經消費者物價指數調整為6,700,000元，試問甲君 112年度應繳納的所得稅為何？', '["1,200,000元", "1,260,000元", "1,460,000元", "1,560,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00177', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '有關所得基本稅額的申報，下列敘述何者正確？①獨資或合夥組織之營利事業無須繳納基本稅額', '["個人只要有屬於應計入基本所得額項目的所得來源，就必須申報基本稅額", "當年度綜合所得總額 未超過免稅額及標準扣除額之合計數，得免辦結算申報者，亦可免計算、申報及繳納基本稅額", "個 人有屬於應計入基本所得額項目的所得來源，不一定就必須繳納基本稅額。基本稅額應先與一般所得 稅額作比較。如果一般所得稅額高於或等於基本稅額，則不必再繳納基本稅額", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00178', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據營利事業所得稅查核準則，有關折舊費用之提列，下列敘述何者錯誤？', '["自93年1月1日起經營小客車租賃業務之營利事業新購置乘人小客車，以不超過新臺幣500萬元 為限，依規定耐用年數計提折舊，超提之折舊不予認定", "營利事業選擇加速折舊獎勵者，以依所得稅法第51條規定，採用平均法及定率遞減法折舊方法為限", "裝修費或重大檢查費屬於資本支出者，不得併入該項資產之實際成本餘額內計算，亦不得計算折舊， 以避免虛增費用", "營利事業持有之不動產，依國際會計準則第40號或企業會計準則公報第16號規定認列為投資性不 動產，房屋部分應按不短於固定資產耐用年數表規定之耐用年數計提折舊費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00179', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據營利事業所得稅查核準則有關捐贈認列費用之規定，下列敘述何者正確？', '["營利事業指定對特定學校法人或私立學校之捐款得列為費用，但以不超過其所得額30%為限", "營利事業依運動產業發展條例第26條之二第三項規定對經中央主管機關專案核准之重點職業或業 餘運動業，及經中央主管機關公告之重點運動賽事主辦單位之捐贈，得按捐贈金額之150%，自所得額 中減除", "營利事業依政治獻金法第19條第2項規定，對政黨、政治團體及擬參選人之捐贈得列為費用，以 不超過所得額20%為限，其總額並不得超過新臺幣250萬元", "營利事業為協助國防建設、慰勞軍隊、對各級政府、及經財政部專案核准之捐贈，以新臺幣 2,000 萬元為限，自所得額中減除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00180', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據營利事業所得稅查核準則之規定，旅費支出，應提示詳載逐日前往地點、訪洽對象及內容等之出 差報告單及相關文件，足資證明與營業有關者，憑以認定；其未能提出者，應不予認定。其中有關搭 乘各種交通工具之交通費核銷憑證，下列何種情形准以經手人（即出差人）之證明為憑，核實認定？', '["租賃之包車費", "搭乘國內航線之飛機", "搭乘國際航線之飛機", "搭乘高速鐵路當日往返"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00181', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國現行營利事業所得稅查核準則，有關營利事業呆帳損失之列支以及備抵呆帳之提列，下列敘述何 者正確？', '["債務人倒閉、逃匿、重整、和解或破產之宣告，或其他原因，致債權之一部或全部不能收回者，視 為實際發生呆帳損失，並應於發生當年度沖抵備抵呆帳", "債權中有逾期一年，經催收後，未經收取本金或利息者，視為實際發生呆帳損失，並應於發生當年 度沖抵備抵呆帳", "提列備抵呆帳，以應收帳款及應收票據為限，並包括已貼現之票據", "備抵呆帳餘額，最高不得超過應收帳款及應收票據餘額之3%；其為金融業者，則以其債權餘額估 列之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
